function useCountUp(target, duration = 2000, start = false) {
  const [count, setCount] = useState(0);
  useEffect(() => {
    if (!start) return;
    let startTime = null;
    const step = (timestamp) => {
      if (!startTime) startTime = timestamp;
      const progress = Math.min((timestamp - startTime) / duration, 1);
      const eased = 1 - Math.pow(1 - progress, 3);
      setCount(Math.floor(eased * target));
      if (progress < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [target, duration, start]);
  return count;
}

function StatCard({ stat, index, visible }) {
  const count = useCountUp(stat.number, 2000, visible);

  return (
    <div
      className="flex flex-col items-center text-center group"
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(40px)",
        transition: `opacity 0.6s ease ${index * 0.15}s, transform 0.6s ease ${index * 0.15}s`,
      }}
    >
      {/* Illustration */}
      <div className="w-36 h-40 mb-6 relative">
        <div
          className="w-full h-full transition-transform duration-300 group-hover:scale-110 group-hover:-translate-y-2"
          style={{ filter: "drop-shadow(0 8px 16px rgba(0,0,0,0.12))" }}
        >
          {stat.fallbackIcon}
        </div>
      </div>

      {/* Number */}
      <div className="text-5xl md:text-6xl font-black text-gray-900 mb-3 tracking-tight font-mono">
        {count.toLocaleString()}
        <span className="text-[#D5AD36]">{stat.suffix}</span>
      </div>

      {/* Label */}
      <p className="text-gray-600 font-semibold text-base md:text-lg tracking-wide">
        {stat.label}
      </p>
    </div>
  );
}

export default function WinningRecord() {
  const [visible, setVisible] = useState(false);
  const sectionRef = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.2 }
    );
    if (sectionRef.current) observer.observe(sectionRef.current);
    return () => observer.disconnect();
  }, []);

  // Trigger on mount for artifact preview
  useEffect(() => {
    const t = setTimeout(() => setVisible(true), 300);
    return () => clearTimeout(t);
  }, []);

  return (
    <section ref={sectionRef} className="bg-white py-20 px-6">
      {/* Title */}
      <div
        style={{
          opacity: visible ? 1 : 0,
          transform: visible ? "translateY(0)" : "translateY(-20px)",
          transition: "opacity 0.6s ease, transform 0.6s ease",
        }}
        className="text-center mb-16"
      >
        <h2 className="text-4xl md:text-5xl font-bold text-[#0E0C4F]">
          Our Winning Record
        </h2>
        <div className="mt-3 mx-auto w-16 h-1 rounded-full bg-[#D5AD36]" />
      </div>

      {/* Stats Grid */}
      <div className="max-w-5xl mx-auto grid grid-cols-2 md:grid-cols-4 gap-10 md:gap-6">
        {stats.map((stat, index) => (
          <StatCard key={stat.label} stat={stat} index={index} visible={visible} />
        ))}
      </div>
    </section>
  );
}